scwin.f_DefaultValue = function (gubun) {
  switch (gubun) {
    case "Create":
      chb_frpc1.setValue("1");
      chb_frpc2.setValue("0");
      chb_otpc1.setValue("1");
      chb_otpc2.setValue("0");
      ds_hmhno.removeAll();
      scwin._resetAutoComplete(lc_hmhno);
      // ed_mftpacd.setValue("");
      scwin.txt_unit = "";
      ed_srno.setValue("");
      ed_mblno.setValue("");
      $c.gus.cfEnableObjects($p, [ed_srno]);
      $c.gus.cfEnableObjects($p, [ed_mblno]);
      rd_cgtype.setValue("L");
      rd_tplgb.setValue("N");
      ed_cucd.setValue("KRW");
      ed_acif1.setValue("FREIGHT PREPAID");
      ed_dvcr.setValue("N.V.D");
      ed_dvct.setValue("");
      ed_insu.setValue("NIL");
      rd_ergb.setValue("E");
      ed_blno.setValue("");
      ed_blno.focus();
      break;
    case "Copy":
      ed_blno.setValue("");
      ds_hmhno.removeAll();
      scwin._resetAutoComplete(lc_hmhno);
      // ed_mftpacd.setValue("");
      scwin.txt_unit = "";
      ed_srno.setValue("");
      ed_mblno.setValue("");
      scwin.hd_oldmhno = "";
      ed_blno.focus();
      break;
    default:
      break;
  }
};

