//-------------------------------------------------------------------------
// 저장
//-------------------------------------------------------------------------
scwin.f_Save = async function () {
  if (scwin.actionFlag == "Create" || scwin.actionFlag == "Copy") {
    await scwin.f_ProcessBinding(ds_HouseBillSearch, "HouseBillSearch");
    await $c.sbm.execute($p, sbm_RetrieveHouseBillCheck);
  }
  await scwin.f_Save_after();
};
scwin.f_Save_after = async function () {
  scwin.f_FreightTypeSetting();
  if (ds_HouseBillInfo.getModifiedIndex().length > 0 || ds_HouseLicenseInfo.getModifiedIndex().length > 0) {
    // scwin._syncHiddenToDs();
    await scwin.f_ProcessBinding(ds_HouseBillInfo, "HouseBillSave");
    await scwin.f_ProcessBinding(ds_HouseLicenseInfo, "HouseLicenseSave");
    scwin.f_selectTabMenu(0); // 저장 전 TAB FOCUS  이동
    scwin.f_FreightTypeSetting();
    if (await scwin.f_ReqFieldChk()) {
      scwin.actionFlag = "Save";
      scwin.f_HblNoStockPram();
      var hbRowIndex = scwin._getRowIndex(ds_HouseBillInfo);
      if ($c.str.trim($p, ed_agcd.getValue()) == "") {
        ds_HouseBillInfo.setCellData(hbRowIndex, "shipgb", "C");
      } else {
        ds_HouseBillInfo.setCellData(hbRowIndex, "shipgb", "L");
      }

      // UserStatus-JSP 화면에 Head 와 Body(그리드)가 있을경우 Body가 변경 될 경우 무조건 Head도 서버 로 전송 해서 업데이트 하기 위해서 사용 됨
      if (ds_HouseBillInfo.getCellData(hbRowIndex, "status") == "U") {
        ds_HouseBillInfo.setCellData(hbRowIndex, "status", "");
      } else {
        ds_HouseBillInfo.setCellData(hbRowIndex, "status", "U");
      }
      if (ed_shCtcd.getValue() == "") {
        await $c.win.alert($p, "Shipper Country code is mandatory.");
        return false;
      }
      if (ed_cnCtcd.getValue() == "") {
        await $c.win.alert($p, "Consignee Country code is mandatory.");
        return false;
      }
      if (ed_mwarecd.getValue() == "") {
        await $c.win.alert($p, "적재장소는 필수입니다.");
        return false;
      }
      if (ed_warecd.getValue() == "") {
        await $c.win.alert($p, "장치장소는 필수입니다.");
        return false;
      }

      // B/L PIC값이 없을때 등록자 아이디로 입력(PIC값이 null되는걸 방지)
      if (ed_blpic.getValue() == "") {
        txt_blpic.setValue("");
        ds_HouseBillInfo.setCellData(hbRowIndex, "pic", scwin.userId);
      }
      await $c.sbm.execute($p, sbm_Save);
    }
  } else {
    await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_001, ["House Info"]); //@은(는) 변경된 사항이 없습니다.
  }
};

//유효성검사
scwin.f_ReqFieldChk = async function () {
  if (ed_srno.getValue() == "") {
    await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_002, ["Booking No"]);
    ed_srno.focus();
    return false;
  }
  if (txt_shnm1.getValue() == "") {
    await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_002, ["Shipper Name"]);
    txt_shnm1.focus();
    return false;
  }
  if (txt_shnm2.getValue() == "") {
    await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_002, ["Shipper Name"]);
    txt_shnm2.focus();
    return false;
  }
  if (txt_cnnm1.getValue() == "") {
    await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_002, ["Consignee Name"]);
    txt_cnnm1.focus();
    return false;
  }
  if (txt_cnnm2.getValue() == "") {
    await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_002, ["Consignee Name"]);
    txt_cnnm2.focus();
    return false;
  }
  if (ed_srno.getValue() == "") {
    await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_002, ["Booking No"]);
    ed_srno.focus();
    return false;
  }
  if (ed_ondt.getValue() == "") {
    await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_002, ["Onboard Date"]);
    ed_ondt.focus();
    return false;
  }
  if (ed_avdt.getValue() == "") {
    await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_002, ["Arrival Date"]);
    ed_avdt.focus();
    return false;
  }

  // 날짜 범위 확인
  if (!$c.gus.cfIsAfterDate($p, ed_ondt.getValue(), ed_avdt.getValue())) {
    await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_048, ["Onboard Date", "Arrival Date"]); //@은(는) 보다 작아야 합니다.
    ed_ondt.focus();
    return false;
  }

  //ETD-ETA가 저장하는 날짜로 부터 3개월 이상의 미래일 수 없다.
  if ($c.gus.cfMonthsBetween($p, scwin._toDate(scwin.strCurDate), scwin._toDate(ed_ondt.getValue())) > 3) {
    await $c.win.alert($p, "Onboard Date가 저장하는 날짜로 부터 3개월 이상의 미래일 수 없습니다.");
    tab_main.setSelectedTabIndex(0);
    ed_ondt.focus();
    return false;
  }

  //ETD-ETA가 저장하는 날짜로 부터 3개월 이상의 미래일 수 없다.
  if ($c.gus.cfMonthsBetween($p, scwin._toDate(scwin.strCurDate), scwin._toDate(ed_avdt.getValue())) > 3) {
    await $c.win.alert($p, "Arrival Date가 저장하는 날짜로 부터 3개월 이상의 미래일 수 없습니다.");
    tab_main.setSelectedTabIndex(0); // 1번째 탭으로 이동.
    ed_avdt.focus();
    return false;
  }

  //ETD-ETA가 3년 이상의 과거 일 수 없다.
  if ($c.gus.cfYearsBetween($p, scwin._toDate(ed_ondt.getValue()), scwin._toDate(scwin.strCurDate)) > 3) {
    await $c.win.alert($p, "Onboard Date가 3년 이상의 과거 일 수 없습니다.");
    tab_main.setSelectedTabIndex(0); // 1번째 탭으로 이동.
    ed_ondt.focus();
    return false;
  }

  //ETD-ETA가 3년 이상의 과거 일 수 없다.
  if ($c.gus.cfYearsBetween($p, scwin._toDate(ed_avdt.getValue()), scwin._toDate(scwin.strCurDate)) > 3) {
    await $c.win.alert($p, "Arrival Date가 3년 이상의 과거 일 수 없습니다.");
    tab_main.setSelectedTabIndex(0); // 1번째 탭으로 이동.
    ed_avdt.focus();
    return false;
  }

  //ETA-ETD(transit time)가 150일을 초과할 수 없다.  *150일(총 운항DATE 수) : ETA날짜에서 ETD날짜를 빼고 +1 한 날짜 
  if ($c.date.diffDate($p, scwin._toDate(ed_ondt.getValue()), scwin._toDate(ed_avdt.getValue())) > 149) {
    await $c.win.alert($p, "Onboard Date-Arrival Date(transit time)가 150일을 초과할 수 없습니다.");
    tab_main.setSelectedTabIndex(0); // 1번째 탭으로 이동.
    ed_ondt.focus();
    return false;
  }
  if (ed_dept.getValue() == "") {
    await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_002, ["Department Info"]);
    ed_dept.focus();
    return false;
  }
  if (ed_sacd.getValue() == "") {
    await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_002, ["Salesman Info"]);
    ed_sacd.focus();
    return false;
  }
  if (ed_itcd.getValue() == "") {
    await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_002, ["Item Info"]);
    ed_itcd.focus();
    return false;
  }
  if (ed_ediwht.getValue() == "" || ed_ediwht.getValue() == "0") {
    ed_ediwht.setValue(ed_mftwht.getValue());
  }
  if (ed_cjdt.getValue() == "" || !$c.date.isDate($p, ed_cjdt.getValue())) {
    // cfValidateValue = date맞는지유효성검사
    await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_002, ["Result Date Date"]);
    ed_cjdt.focus();
    return false;
  }
  if (ds_HouseLicenseInfo.getTotalRow() > 0) {
    if (txt_ngnm1.getValue() == "") {
      scwin.f_selectTabMenu(2); //  TAB FOCUS  이동
      await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_002, ["Nature of Goods Info"]);
      txt_ngnm1.focus();
      return false;
    }
  }
  if (ed_dept.getValue() == "1GG") {
    await $c.gus.cfAlertMsg($p, scwin.MSG_LO_WRN_010, ["Department Info"]);
    ed_dept.focus();
    return false;
  }
  if (ds_customerInfo.getTotalRow() > 0) {
    if (ed_dept.getValue() != ds_customerInfo.getCellData(ds_customerInfo.getRowPosition() || 0, "col1")) {
      await $c.gus.cfAlertMsg($p, scwin.MSG_LO_WRN_013);
      ed_dept.focus();
      return false;
    }
  }
  if ((await $c.gus.cfValidate($p, [tb_searchCondition, tb_master1, gr_HouseLicenseInfo])) == false) {
    return false;
  }
  for (var i = 0; i < ds_HouseLicenseInfo.getTotalRow(); i++) {
    //면장 번호가 있을 경우 포장 갯수 , 중량은 반드시 0보다 커야 한다
    if (ds_HouseLicenseInfo.getCellData(i, "exno") != "") {
      if (ds_HouseLicenseInfo.getCellData(i, "pkgs") == "0") {
        scwin.f_selectTabMenu(2);
        await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_002, ["포장 갯수"]); //@는 필수입력항목입니다.
        return false;
      }
      if (ds_HouseLicenseInfo.getCellData(i, "wht") == "0") {
        scwin.f_selectTabMenu(2);
        await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_002, ["중량"]); //@는 필수입력항목입니다.
        return false;
      }
    }

    //분할 여부가 yes일경우 분할 차수는 필수
    if (ds_HouseLicenseInfo.getCellData(i, "elsplgb") == "Y") {
      if (ds_HouseLicenseInfo.getCellData(i, "elmid") == "") {
        scwin.f_selectTabMenu(2);
        await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_002, ["분할 차수 "]); //@는 필수입력항목입니다.
        return false;
      }
    }

    //동시 포장 기호가 있을 경우 동시 포장 수랑 , 단위 필
    if (ds_HouseLicenseInfo.getCellData(i, "elcogb") != "") {
      if (ds_HouseLicenseInfo.getCellData(i, "eldpkg") == "0") {
        scwin.f_selectTabMenu(2);
        await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_002, ["동시 포장 수량"]); //@는 필수입력항목입니다.
        return false;
      }
      if (ds_HouseLicenseInfo.getCellData(i, "eldpkgut") == "") {
        scwin.f_selectTabMenu(2);
        await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_002, ["동시포장단위"]); //@는 필수입력항목입니다.
        return false;
      }
    }
  }
  return true;
};

