//-------------------------------------------------------------------------
//House no Change
//-------------------------------------------------------------------------
scwin.f_HawbNoChange = async function () {
  if ($c.str.trim($p, ed_blno.getValue()) != "") {
    var opts = {
      id: "",
      popupName: "",
      modal: true,
      type: "browserPopup",
      title: "Win pop",
      width: 460,
      height: 280
    };
    var data = {
      pBlno: ed_blno.getValue()
    };
    var rtnList = await $c.win.openPopup($p, "/ui/il/common/xml/ilCommonHawbNoChange.xml", opts, data);

    // 02.03 ilCommonHawbNoChange 팝업 개발X
    if (rtnList != null) {
      if (rtnList[0] == "N/A" && $c.str.trim($p, rtnList[1]) != "") {
        ds_HblNoChangeParam.removeAll();
        scwin._insertRow(ds_HblNoChangeParam);
        var rowIndex = scwin._getRowIndex(ds_HblNoChangeParam);
        var hbRowIndex = scwin._getRowIndex(ds_HouseBillInfo);
        ds_HblNoChangeParam.setCellData(rowIndex, "odrNo", ds_HouseBillInfo.getCellData(hbRowIndex, "odrNo")); // Order No
        ds_HblNoChangeParam.setCellData(rowIndex, "kcomcd", scwin.hd_kcomcd); // 법인코드
        ds_HblNoChangeParam.setCellData(rowIndex, "blNo", $c.str.trim($p, ed_blno.getValue())); // House Bill No
        ds_HblNoChangeParam.setCellData(rowIndex, "newblNo", $c.str.trim($p, rtnList[1])); // 변경할 House Bill No
        ds_HblNoChangeParam.setCellData(rowIndex, "mhno", $c.str.trim($p, lc_hmhno.getValue() || "")); // Consol No

        scwin.spMsg = "";
        scwin.spRtn = "-1";
        if (await $c.win.confirm($p, E_MSG_CM_CRM_001)) {
          let e = await $c.sbm.execute($p, sbm_HblNoChange);
          console.log(e);
          if (e.responseJSON.resultDataSet[0].Code < 0) return;

          // if (ds_HblNoChangeResult.getRowCount() > 0) {
          if (e.responseJSON.OUT_DS1.length > 0) {
            var resultRowIndex = scwin._getRowIndex(ds_HblNoChangeResult);
            scwin.spMsg = ds_HblNoChangeResult.getCellData(resultRowIndex, "spMsg");
            scwin.spRtn = ds_HblNoChangeResult.getCellData(resultRowIndex, "spRtn");
          }
          if (scwin.spRtn == "0") {
            // 변경 성공
            ed_blno.setValue($c.str.trim($p, rtnList[1]));
            lc_hmhno.focus();
            await $c.gus.cfAlertMsg($p, scwin.MSG_LO_WRN_007);
          } else if (scwin.spRtn == "-2") {
            //새로운 번호가 존재 하는 경우 오류
            await $c.gus.cfAlertMsg($p, scwin.spMsg);
          } else {
            await $c.gus.cfAlertMsg($p, scwin.MSG_LO_WRN_006);
          }
        }
      }
    }
  }
};

//-------------------------------------------------------------------------
//부서  Change
//-------------------------------------------------------------------------
scwin.f_departmentChange = async function () {
  if ($c.str.trim($p, ed_dept.getValue()) != "") {
    var opts = {
      id: "popDeptChange",
      popupName: "부서변경",
      modal: true,
      type: "browserPopup",
      title: "Win pop",
      width: 460,
      height: 280
    };
    var data = {
      pdept: ed_dept.getValue(),
      pdeptnm: txt_deptnm.getValue()
    };
    var rtnList = await $c.win.openPopup($p, "/ui/il/common/xml/ilCommonDeptChange.xml", opts, data);
    if (rtnList != null) {
      if (rtnList[0] == "N/A" && $c.str.trim($p, rtnList[1]) != "" && $c.str.trim($p, rtnList[2]) != "") {
        if ($c.str.trim($p, rtnList[1]) == "1GG") {
          await $c.gus.cfAlertMsg($p, scwin.MSG_LO_WRN_010, ["Department Info"]);
          return false;
        }
        ds_DeptChangeParam.removeAll();
        scwin._insertRow(ds_DeptChangeParam);
        var rowIndex = scwin._getRowIndex(ds_DeptChangeParam);
        var hbRowIndex = scwin._getRowIndex(ds_HouseBillInfo);
        ds_DeptChangeParam.setCellData(rowIndex, "modrNo", "");
        if (ds_HouseBillInfo.getRowCount() > 0) {
          ds_DeptChangeParam.setCellData(rowIndex, "hodrNo", ds_HouseBillInfo.getCellData(hbRowIndex, "odrNo"));
        } else {
          ds_DeptChangeParam.setCellData(rowIndex, "hodrNo", "");
        }
        ds_DeptChangeParam.setCellData(rowIndex, "kcomcd", scwin.hd_kcomcd);
        ds_DeptChangeParam.setCellData(rowIndex, "dept", rtnList[1]);
        ds_DeptChangeParam.setCellData(rowIndex, "deptnm", rtnList[2]);
        scwin.spMsg = "";
        scwin.spRtn = "-1";
        if (await $c.win.confirm($p, $c.data.getMessage($p, E_MSG_CM_CRM_001))) {
          await $c.sbm.execute($p, sbm_DeptChange);
          if (e.responseJSON.resultDataSet[0].Code < 0) return;
          if (ds_DeptChangeResult.getRowCount() > 0) {
            var resultRowIndex = scwin._getRowIndex(ds_DeptChangeResult);
            scwin.spMsg = ds_DeptChangeResult.getCellData(resultRowIndex, "spMsg");
            scwin.spRtn = ds_DeptChangeResult.getCellData(resultRowIndex, "spRtn");
          }
          if (scwin.spRtn == "0") {
            txt_deptnm.setValue($c.str.trim($p, rtnList[2]));
            ed_dept.setValue($c.str.trim($p, rtnList[1]));
            await $c.gus.cfAlertMsg($p, scwin.MSG_LO_WRN_009);
          } else if (scwin.spRtn == "-2") {
            await $c.gus.cfAlertMsg($p, scwin.MSG_LO_WRN_013);
          } else {
            await $c.gus.cfAlertMsg($p, scwin.MSG_LO_WRN_008);
          }
        }
      }
    }
  }
};

