scwin.sbm_Save_submitdone = async function (e) {
  if (e.responseJSON.resultDataSet[0].Code < 0) return;
  if (scwin.actionFlag == "Save") {
    // 저장
    if (ds_resultHblnoMsg.getTotalRow() > 0) {
      var rowIndex = scwin._getRowIndex(ds_resultHblnoMsg);
      if ($c.str.trim($p, ds_resultHblnoMsg.getCellData(rowIndex, "Hblno")) != "") {
        ed_blno.setValue(ds_resultHblnoMsg.getCellData(rowIndex, "Hblno"));
      }
    }
    await $c.gus.cfAlertMsg($p, E_MSG_CM_INF_001);

    // f_Save script
    scwin.f_Set("SAVE");
    scwin.f_MhnoLoading();
    await scwin.f_Retrieve();
  }
  if (scwin.actionFlag == "Delete") {
    // 삭제
    await $c.gus.cfAlertMsg($p, E_MSG_CM_INF_004); // 성공적으로 삭제하였습니다
    ed_blno.setValue("");
    ds_hmhno.removeAll();
    scwin._resetAutoComplete(lc_hmhno); // TODO: CBData 매핑 확인
    ed_blno.focus();
  }
  scwin.processFlag = "None";
};
