scwin._getRowIndex = function (ds) {
  return ds.getRowPosition() == null || ds.getRowPosition() < 0 ? 0 : ds.getRowPosition(); // TODO: row/index 보정 필요 여부 화면별 확인
};
scwin._getObj = function (id) {
  return $c.gus.object ? $c.gus.object($p, id) : null;
};
scwin._getValueById = function (id) {
  var obj = scwin._getObj(id);
  return obj ? obj.getValue() : "";
};
scwin._setValueById = function (id, value) {
  var obj = scwin._getObj(id);
  if (obj) {
    obj.setValue(value);
  }
};
scwin._clearValues = function (ids) {
  for (var i = 0; i < ids.length; i++) {
    scwin._setValueById(ids[i], "");
  }
};
scwin._syncHiddenFromDs = function () {
  if (ds_HouseBillInfo.getRowCount() == 0) {
    scwin._setValueById("hd_frpc", "");
    scwin._setValueById("hd_otpc", "");
    scwin._setValueById("hd_oldmhno", "");
    scwin._setValueById("ed_attn", "");
    scwin._setValueById("chb_rider", "");
    scwin._setValueById("chb_endgb", "");
    return;
  }
  var row = scwin._getRowIndex(ds_HouseBillInfo);
  scwin._setValueById("hd_frpc", ds_HouseBillInfo.getCellData(row, "frpc") || "");
  scwin._setValueById("hd_otpc", ds_HouseBillInfo.getCellData(row, "otpc") || "");
  scwin._setValueById("hd_oldmhno", ds_HouseBillInfo.getCellData(row, "oldmhno") || "");
  scwin._setValueById("ed_attn", ds_HouseBillInfo.getCellData(row, "updid") || "");
  scwin._setValueById("chb_rider", ds_HouseBillInfo.getCellData(row, "rider") || "");
  scwin._setValueById("chb_endgb", ds_HouseBillInfo.getCellData(row, "endgb") || "");
};
scwin._syncHiddenToDs = function () {
  if (ds_HouseBillInfo.getRowCount() == 0) {
    return;
  }
  var row = scwin._getRowIndex(ds_HouseBillInfo);
  ds_HouseBillInfo.setCellData(row, "frpc", scwin._getValueById("hd_frpc") || "");
  ds_HouseBillInfo.setCellData(row, "otpc", scwin._getValueById("hd_otpc") || "");
  ds_HouseBillInfo.setCellData(row, "oldmhno", scwin._getValueById("hd_oldmhno") || "");
  ds_HouseBillInfo.setCellData(row, "updid", scwin._getValueById("ed_attn") || "");
  ds_HouseBillInfo.setCellData(row, "rider", scwin._getValueById("chb_rider") || "");
  ds_HouseBillInfo.setCellData(row, "endgb", scwin._getValueById("chb_endgb") || "");
};
scwin._resetAutoComplete = function (obj) {
  if (!obj) {
    return;
  }
  if (obj.setValue) {
    obj.setValue("");
  }
  if (obj.setSelectedIndex) {
    obj.setSelectedIndex(-1);
  }
};
scwin._bindOnBlur = function (id, handler) {
  var obj = scwin._getObj(id);
  if (!obj && id.indexOf("ed_") == 0) {
    obj = scwin._getObj("udc_" + id.substring(3));
  }
  if (!obj) {
    return;
  }
  if (obj.addEventListener) {
    obj.addEventListener("onblur", handler);
  } else if (obj.setEventHandler) {
    obj.setEventHandler("onblur", handler);
  } else {
    // TODO: UDC 이벤트 바인딩 방식 확인
  }
};
scwin._resolveObj = function (id) {
  var obj = scwin._getObj(id);
  if (!obj && id.indexOf("ed_") == 0) {
    obj = scwin._getObj("udc_" + id.substring(3));
  }
  return obj;
};
scwin._isModified = function (id) {
  var obj = scwin._resolveObj(id);
  if (!obj) {
    return true;
  }
  if (typeof obj.getModified == "function") {
    return obj.getModified();
  }
  if (typeof obj.isModified == "function") {
    return obj.isModified();
  }
  if (typeof obj.modified != "undefined") {
    return obj.modified;
  }
  return true;
};
scwin._setRowStatus = function (ds, rowIndex, status) {
  if (!ds) {
    return;
  }
  if (typeof ds.modifyRowStatus == "function") {
    ds.modifyRowStatus(rowIndex, status);
  } else if (typeof ds.setRowStatus == "function") {
    ds.setRowStatus(rowIndex, status);
  }
};
scwin._ensureRow = function (ds) {
  if (!ds || typeof ds.getRowCount != "function") {
    return;
  }
  if (ds.getRowCount() == 0) {
    scwin._insertRow(ds);
  }
};
scwin._insertRow = function (ds) {
  if (!ds || typeof ds.getRowCount != "function") {
    return -1;
  }
  var rowIndex = ds.getRowCount();
  if (typeof ds.insertRow == "function") {
    ds.insertRow(rowIndex);
  } else if (typeof ds.addRow == "function") {
    ds.addRow();
    rowIndex = ds.getRowCount() - 1;
  }
  return rowIndex;
};
scwin._toDate = function (v) {
  if (v instanceof Date) return v;
  var s = String(v || "");
  var m = s.match(/^(\d{4})(\d{2})(\d{2})$/);
  if (m) {
    return new Date(Number(m[1]), Number(m[2]) - 1, Number(m[3]));
  }
  var d = new Date(s);
  return isNaN(d.getTime()) ? null : d;
};
scwin._openCommonPopup = async function (url, opts, data, callback) {
  var ret = await $c.win.openPopup($p, url, opts, data);
  if (typeof callback == "function") {
    callback(ret);
  }
  return ret;
};

